import { useState } from 'react';
import { useNavigate, Link, NavLink } from 'react-router-dom';

import constFlaskURL from '../../consts/constFlaskURL'


function RoadsSings() {
    const [tableData, setTableData] = useState([]);
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleLogout = async () => {
        setLoading(true);

        try 
        {
            const response = await constFlaskURL.post('/logout');

            if (response.status === 200) 
            {
                setTimeout(() => {
                    navigate('/login');
                }, 1000);
            }
        }
        catch (err) 
        {
            console.error('Logout error:', err);
        } 
        finally 
        {
            setLoading(false);
        }
    };


    const transformDataForTable = (data) => {
        if (!Array.isArray(data) || data.length === 0) 
        {
            return [];
        }

        return data.map(
            (item, index) => (
                {
                    id: index + 1,
                    ...item
                }
            )
        );
    };

    // Delete
    const deleteRoad = async (id) => {
        try {
            await constFlaskURL.delete(`/roads?id=${id}`);
            fetchTableData()
        } catch (error) {
            console.log(error);
        } 
    }

    // Put
    const updateRoad = async (id) => {
        try {
            await constFlaskURL.get(`/road?id=${id}`);
            navigate(`/road/edit/${id}`);
        } catch (error) {
            console.log(error);
        } 
    }

    const fetchTableData = useCallback(async () => {
        setLoading(true);

        try 
        {
            const response = await constFlaskURL.get('/roads/sings');

            if (response.status === 200) 
            {
                setTableData(Array.isArray(response.data) ? response.data : [response.data]);
            }
        } 
        catch (err) 
        {
            console.log(err);
        } 
        finally 
        {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchTableData();
    }, [fetchTableData]);

    const transformedData = transformDataForTable(tableData);

    return (
        <div> 
            {loading ? 
            (
                <div>
                    <p>Загрузка данных...</p>
                </div>
            ) : transformedData.length > 0 ? 
            (
                <div>
                    <nav className='navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0'>
                        <div className='container-fluid py-2'>
                            <Link className='navbar-brand fs-3 fw-bold' to='/main'>roads_admin</Link>
                            <div class="btn-group">
                                <button type="button" class="btn btn-info">Пользователь</button>
                                <button type="button" class="btn btn-info dropdown-toggle dropdown-toggle-split" data-bs-toggle="dropdown" aria-expanded="false">
                                    <span class="visually-hidden">Переключатель выпадающего списка</span>
                                </button>
                                <ul class="dropdown-menu">
                                    <li>
                                        <a class="dropdown-item">
                                            <button
                                                onClick={handleLogout} 
                                                className='dropdown-item'
                                                disabled={loading}
                                            >
                                            {loading ? (
                                                <>
                                                    <span className='spinner'></span>
                                                    Выход...
                                                </>
                                                ) : 'Выйти'}
                                            </button>
                                        </a>
                                    </li>
                                </ul>
                            </div>
                        </div>
                        <div className='container-fluid bg-dark py-2'>
                            <div className='navbar-nav flex-row'>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/main' end> Главная </NavLink>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/roads' end> Дороги </NavLink>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/sings' end> Дорожные знаки </NavLink>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/roads/sings' end> Знаки на дорогах </NavLink>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/type_crossroad' end> Типы перекрестков </NavLink>
                            </div>
                        </div>
                    </nav>
                    <div className='container'>
                        <p className='Table-header'><h1>Знаки на дорогах.</h1></p>
                        <table className='table table-striped'>
                            <thead>
                                <tr>
                                    <th scope='col'>ID</th>
                                    <th scope='col'>Название дороги</th>
                                    <th scope='col'>Номер дороги</th>
                                    <th scope='col'>Изображение</th>
                                    <th scope='col'>Широта</th>
                                    <th scope='col'>Долгота</th>
                                    <th scope='col'>Название дорожного знака</th>
                                    <th scope='col'>ID дорожного знака</th>
                                    <th scope='col'>
                                        Операции  
                                        <button type='button' className='btn btn-success btn-sm me-1' onClick={() => navigate('/road/add')}>
                                            Создать
                                        </button>
                                    </th>
                                </tr>
                            </thead>
                            <tbody>
                                {tableData[0]?.items.map((roadsing) =>(
                                    <tr key={roadsing.id}>
                                        <th>{roadsing.id}</th>
                                        <td>{roadsing.name_road}</td>
                                        <td>{roadsing.number_road}</td>
                                        <td>{roadsing.sings.image}</td>
                                        <td>{roadsing.sings.lantitude}</td>
                                        <td>{roadsing.sings.longitude}</td>
                                        <td>{roadsing.sings.sing_id}</td>
                                        <td>
                                            <button type='button' className='btn btn-primary btn-sm me-1' onClick={() => updateRoad(road.id)}>
                                                Редактировать
                                            </button>
                                            <button type='button' className='btn btn-danger btn-sm' onClick={() => deleteRoad(road.id)}>
                                                Удалить
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            ) : (
                <p className='no-data'>Нет данных для отображения</p> 
            )} 
        </div>
    );
}

export default RoadsSings;
